INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-acfc4025-moex-00021', 'elementary-acfc4025', 'elementary-acfc4025-moex-114-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '為避免酒駕憾事再度發生，2022年1月立法院三讀通過《中華民國刑法》，其中第185條之3之刑度， 由「2 年以下有期徒刑、得併科 20 萬元以下罰金」提升為「3 年以下有期徒刑、得併科 30 萬元以下罰 金」；酒駕致重傷維持「1年以上、7年以下有期徒刑」刑期，但增訂「得併科100萬元以下罰金」規定。 請問下列敘述何者正確？', '["酒駕致重傷增訂之刑責規定，意指若罰金繳納後，便無需接受有期徒刑之懲處", "於立法程序之「二讀」階段，立法委員針對本次修法內容逐項深入討論之", "按法規內容可知，酒駕之懲處隸屬於「生命刑、自由刑、財產刑」之範疇", "就本次修法內容可知，增訂之刑責與「追徵、追繳或抵償」皆屬從刑之範疇"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:23+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "517", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00022', 'elementary-acfc4025', 'elementary-acfc4025-moex-114-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '某學者指出：「針對重大公共決策，民選政府可以不採納專家意見，但不應該忽略或扭曲專家意見。例如， 民主的發展中國家不引進已開發國家藥廠專家所開發的有效療法，民選政府可以以各種合理理由拒絕，並 向專家與社會大眾說明，但不應基於特定政治考量，向大眾傳播該療法無效的不實說法。」下列何者最符 合以上敘述的要旨？', '["民選政府制定公共政策不採納專家意見，不符合民主精神", "發展中國家政府採購已開發國家藥廠的藥品會延續殖民主義的剝削", "民選政府在公共決策過程中審慎考量專家意見有助於民主與治理", "民主國家中，不採納專家意見的政府就是民粹政府"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:23+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "517", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00023', 'elementary-acfc4025', 'elementary-acfc4025-moex-114-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '依據我國憲法規定及大法官解釋之意旨，關於政黨比例代表制，下列敘述何者正確？', '["憲法增修條文規定，獲得政黨選舉票百分之五以上之政黨，始得分配全國不分區立法委員席次，已違反 憲法上之平等原則", "公職人員選舉罷免法規定，依政黨得票總數比例方式產生之全國不分區立法委員當選人不適用罷免規 定，已違反憲法保障人民罷免權意旨", "憲法增修條文對立法委員之選舉採單一選區兩票制，是有意兼顧選區代表性與政黨多元性，未牴觸民主 共和國與國民主權原則", "依政黨得票總數比例方式產生之全國不分區立法委員，縱喪失其所屬政黨之黨員資格，仍不影響其作為 民意代表之資格"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:23+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "517", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00024', 'elementary-acfc4025', 'elementary-acfc4025-moex-114-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '下列關於權利主體之敘述，何者錯誤？', '["自然人的權利能力始於出生登記", "法人的權利能力始於登記成立", "自然人遭戶政機關除籍，也不影響該自然人的權利能力", "發起人於法人成立後脫離法人團體，也不影響該法人的權利能力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:23+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "517", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00025', 'elementary-acfc4025', 'elementary-acfc4025-moex-114-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '下列關於國際人權公約在我國實踐之敘述，何者錯誤？', '["我國並非聯合國會員國，故批准國際人權公約後無法存放於聯合國", "我國主動邀請國際人權專家至我國審查並提供觀察報告，以代替聯合國國家報告審查", "我國依憲法由立法院依條約案審議程序，主動將人權公約國內法化", "經過我國國內法化之國際人權公約，在規範效力上具有法律的位階"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:23+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "517", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00026', 'elementary-acfc4025', 'elementary-acfc4025-moex-114-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '關於法律的位階，下列何者錯誤？', '["特別法的位階高於普通法", "經立法院通過之國際條約位階等同法律", "法律的位階高於法規命令", "法規命令與憲法牴觸無效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:23+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "517", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00027', 'elementary-acfc4025', 'elementary-acfc4025-moex-114-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '大學生甲認為學校不允許他在學校布告欄張貼支持某政治人物的海報，侵害其言論自由。下列關於救濟途 徑的敘述，何者正確？', '["甲沒有被退學，故不能救濟", "甲應該先向學校提起申訴", "甲得逕向行政法院提起行政訴訟", "甲得逕向憲法法庭聲請判決其基本權是否受侵害"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:23+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "517", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00028', 'elementary-acfc4025', 'elementary-acfc4025-moex-114-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '關於憲法明定之救濟權利，下列何者錯誤？', '["訴訟", "訴願", "請願", "陳情"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:23+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "517", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00029', 'elementary-acfc4025', 'elementary-acfc4025-moex-114-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '關於得行使原住民相關權利之主體，下列何者錯誤？', '["原住民本人", "部落", "各原住民族", "原住民族委員會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:23+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "517", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00030', 'elementary-acfc4025', 'elementary-acfc4025-moex-114-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '國際政治的權力結構是一個動態體系，關於國際政治體系的發展歷程，下列敘述何者正確？', '["冷戰時期的單極體系，指美國在軍事、科技和經濟各方面領先全球", "蘇聯共產政權瓦解後，國際政治權力結構走向多極體系的國際合作", "二次世界大戰後，資本主義與共產主義兩大陣營對峙長達半個世紀", "中國崛起成為世界工廠與世界市場，國際體系轉變為中美兩極對抗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:23+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "517", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL)
